   701	fn column_viewport(area_width: u16, total_cols: usize, focus_col: usize) -> (usize, usize) {
   702	    if total_cols == 0 {
   703	        return (0, 0);
   704	    }
   705	    let width = usize::from(area_width).max(1);
   706	    let max_visible = (width / MIN_MULTI_COLUMN_WIDTH).max(1);
   707	    let visible = total_cols.min(max_visible);
   708	    let focus = focus_col.min(total_cols - 1);
   709	    let mut start = focus.saturating_add(1).saturating_sub(visible);
   710	    let max_start = total_cols.saturating_sub(visible);
   711	    if start > max_start {
   712	        start = max_start;
   713	    }
   714	    (start, visible)
   715	}
