fn column_group_color(label: &str) -> Color {
    let count = label
        .split_whitespace()
        .next()
        .and_then(|v| v.parse::<usize>().ok())
        .unwrap_or(1);
    match count {
        1 => Theme::TEXT_SECONDARY,
        2 => Theme::ACCENT_BLUE,
        3 => Theme::ACCENT_CYAN,
        4 => Theme::ACCENT_TEAL,
        _ => Theme::ACCENT_PURPLE,
    }
}

