/// Try to store a session in git-native branch storage and return the body_url.
/// SQLite mode skips branch storage and falls back to server-side body storage.
fn try_git_store(
    session: &opensession_core::trace::Session,
    config: &config::DaemonConfig,
) -> Option<String> {
    if matches!(config.git_storage.method, config::GitStorageMethod::Sqlite) {
        return None;
    }

    // Get working directory from session context.
    let cwd = working_directory(session)?;

    let repo_root = opensession_git_native::ops::find_repo_root(Path::new(cwd))?;
    let git_ctx = opensession_git_native::extract_git_context(cwd);
    let remote_url = git_ctx.remote?;

    let jsonl = session.to_jsonl().ok()?;
    let branch = opensession_git_native::resolve_ledger_branch(
        git_ctx.branch.as_deref(),
        git_ctx.commit.as_deref(),
    );
    let commit_shas: Vec<String> = git_ctx.commit.clone().into_iter().collect();
    let git_meta = GitMeta {
        remote: Some(remote_url.clone()),
        repo_name: git_ctx.repo_name.clone(),
        branch: Some(branch.clone()),
        head: git_ctx.commit.clone(),
        commits: commit_shas.clone(),
    };
    let target_ref = opensession_git_native::branch_ledger_ref(&branch);
    let meta_json = build_git_storage_meta_json_with_git(session, Some(&git_meta));
    let storage = opensession_git_native::NativeGitStorage;
    match storage.store_session_at_ref(
        &repo_root,
        &target_ref,
        &session.session_id,
        jsonl.as_bytes(),
        &meta_json,
        &commit_shas,
    ) {
        Ok(stored) => Some(opensession_git_native::generate_raw_url(
            &remote_url,
            &stored.commit_id,
            &stored.hail_path,
        )),
        Err(e) => {
            eprintln!("git-native storage: {e}");
            None
        }
    }
}

fn ensure_session_source_path(session: &mut Session, source_path: &Path) {
    let has_source_path = session
        .context
        .attributes
        .get("source_path")
        .and_then(|value| value.as_str())
        .map(str::trim)
        .is_some_and(|value| !value.is_empty());
    if has_source_path {
        return;
    }

    session.context.attributes.insert(
        "source_path".to_string(),
        serde_json::Value::String(source_path.to_string_lossy().to_string()),
    );
}

/// Load sessions from explicit file paths passed as CLI args.
fn load_from_paths(args: &[String]) -> Vec<LoadedSession> {
    let mut sessions = Vec::new();

    for arg in args {
        let path = PathBuf::from(arg);
        if !path.exists() {
            eprintln!("Warning: file not found: {}", path.display());
            continue;
        }
        match opensession_parsers::parse_with_default_parsers(&path) {
            Ok(Some(mut session)) => {
                if is_auxiliary_session(&session) {
                    continue;
                }
                ensure_session_source_path(&mut session, &path);
                if session.stats.event_count > 0 {
                    sessions.push(LoadedSession {
                        source_path: path.clone(),
                        session,
                    });
                } else if session.stats.event_count == 0 {
                    eprintln!("Warning: skipping empty session from {}", path.display());
                }
            }
            Ok(None) => {
                eprintln!("Warning: no parser for {}", path.display());
            }
            Err(e) => {
                eprintln!("Warning: failed to parse {}: {}", path.display(), e);
            }
        }
    }

    sessions.sort_by(|a, b| {
        b.session
            .context
            .created_at
            .cmp(&a.session.context.created_at)
    });
    sessions
}

fn filter_visible_discovered_sessions(
    sessions: Vec<opensession_core::trace::Session>,
) -> Vec<opensession_core::trace::Session> {
    sessions
        .into_iter()
        .filter(|session| !is_auxiliary_session(session))
        .collect()
}

/// Auto-discover sessions from known local paths.
fn load_sessions() -> Vec<LoadedSession> {
    let locations = opensession_parsers::discover::discover_sessions();
    let mut sessions = Vec::new();

    for location in &locations {
        for path in &location.paths {
            // Skip subagent session files
            if opensession_parsers::is_auxiliary_session_path(path) {
                continue;
            }

            if let Ok(Some(mut session)) = opensession_parsers::parse_with_default_parsers(path) {
                if is_auxiliary_session(&session) {
                    continue;
                }
                ensure_session_source_path(&mut session, path);
                // Skip empty sessions (0 events usually means parse was incomplete)
                if session.stats.event_count > 0 {
                    sessions.push(LoadedSession {
                        source_path: path.clone(),
                        session,
                    });
                }
            }
        }
    }

    sessions.sort_by(|a, b| {
        b.session
            .context
            .created_at
            .cmp(&a.session.context.created_at)
    });
    sessions
}

