fn push_wrapped_detail_rows<'a>(
    lines: &mut Vec<Line<'a>>,
    layout: &StreamLayoutSpec,
    text: &str,
    style: Style,
    selected: bool,
) {
    let row_style = if selected {
        Style::new().bg(Theme::BG_SURFACE)
    } else {
        Style::new()
    };
    let detail_width = layout.center.saturating_sub(4).max(1);
    for (index, row) in wrap_display_width(text, detail_width)
        .into_iter()
        .enumerate()
    {
        let row_prefix = if index == 0 { "  " } else { "    " };
        lines.push(stream_row_line(
            layout,
            "",
            &format!("{row_prefix}{row}"),
            "",
            (
                Style::new().fg(Theme::TEXT_MUTED),
                style,
                Style::new().fg(Theme::TEXT_MUTED),
                row_style,
            ),
        ));
    }
}

fn wrap_display_width(text: &str, max_width: usize) -> Vec<String> {
    if max_width == 0 {
        return vec![String::new()];
    }

    let mut rows = Vec::new();
    for segment in text.split('\n') {
        let mut current = String::new();
        let mut current_width = 0usize;
        for ch in segment.chars() {
            let ch_width = UnicodeWidthChar::width(ch).unwrap_or(0);
            if ch_width == 0 {
                continue;
            }

            if current_width + ch_width > max_width {
                if !current.is_empty() {
                    rows.push(std::mem::take(&mut current));
                    current_width = 0;
                }
                if ch.is_whitespace() {
                    continue;
                }
            }

            if ch_width <= max_width {
                current.push(ch);
                current_width += ch_width;
            }
        }

        if !current.is_empty() {
            rows.push(current);
        }
    }

    if rows.is_empty() {
        rows.push(String::new());
    }
    rows
}

fn collect_content_preview_rows(
    event: &Event,
    max_lines: usize,
    summary_hint: Option<&str>,
    show_diff: bool,
) -> Vec<(String, Style)> {
    const DETAIL_PREVIEW_MAX_CHARS: usize = 100;
    let mut rows = Vec::new();
    let mut seen: BTreeSet<String> = BTreeSet::new();
    if let EventType::FileEdit {
        diff: Some(diff), ..
    } = &event.event_type
    {
        if !show_diff {
            return rows;
        }
        for line in diff.lines().take(max_lines) {
            let style = if line.starts_with('+') {
                Style::new().fg(Theme::ACCENT_GREEN)
            } else if line.starts_with('-') {
                Style::new().fg(Theme::ACCENT_RED)
            } else {
                Style::new().fg(Theme::TEXT_MUTED)
            };
            let compact = compact_text_snippet(line, DETAIL_PREVIEW_MAX_CHARS);
            if compact.is_empty() {
                continue;
            }
            if seen.insert(normalize_preview_line(&compact)) {
                rows.push((compact, style));
            }
        }
        return rows;
    }

    for block in &event.content.blocks {
        match block {
            ContentBlock::Text { text } => {
                let remaining = max_lines.saturating_sub(rows.len());
                if let Some(grouped_rows) = collect_grouped_file_reference_rows(text, remaining) {
                    for (text, style) in grouped_rows {
                        let compact = compact_text_snippet(&text, DETAIL_PREVIEW_MAX_CHARS);
                        if compact.is_empty() {
                            continue;
                        }
                        if !seen.insert(normalize_preview_line(&compact)) {
                            continue;
                        }
                        rows.push((compact, style));
                        if rows.len() >= max_lines {
                            return rows;
                        }
                    }
                    continue;
                }

                let mut in_fence = false;
                for line in text.lines() {
                    let trimmed = line.trim();
                    let trimmed_start = line.trim_start();
                    let is_fence =
                        trimmed_start.starts_with("```") || trimmed_start.starts_with("~~~");
                    let is_heading = !in_fence && trimmed_start.starts_with('#');
                    let is_quote = !in_fence && trimmed_start.starts_with('>');
                    let is_list = !in_fence && looks_like_markdown_list_item(trimmed_start);
                    let markdown_signal = in_fence || is_fence || is_heading || is_quote || is_list;

                    if trimmed.is_empty() {
                        continue;
                    }
                    if !markdown_signal && is_low_signal_text_line(trimmed) {
                        continue;
                    }
                    if summary_hint
                        .is_some_and(|summary| detail_line_matches_summary(trimmed, summary))
                    {
                        if is_fence {
                            in_fence = !in_fence;
                        }
                        continue;
                    }
                    let canonical = if is_fence {
                        strip_markdown_fence_marker(trimmed_start)
                    } else if in_fence {
                        trimmed
                    } else if is_heading {
                        strip_markdown_heading_marker(trimmed_start)
                    } else if is_list {
                        strip_markdown_list_marker(trimmed_start)
                    } else if is_quote {
                        strip_markdown_quote_marker(trimmed_start)
                    } else {
                        trimmed
                    };
                    let canonical = strip_inline_markdown_markers(canonical);
                    let compact = compact_text_snippet(&canonical, DETAIL_PREVIEW_MAX_CHARS);
                    if compact.is_empty() {
                        if is_fence {
                            in_fence = !in_fence;
                        }
                        continue;
                    }
                    if !seen.insert(normalize_preview_line(&compact)) {
                        if is_fence {
                            in_fence = !in_fence;
                        }
                        continue;
                    }
                    let (prefix, style) = if is_fence {
                        ("``` ", Style::new().fg(Theme::ACCENT_PURPLE))
                    } else if in_fence {
                        ("| ", Style::new().fg(Theme::ACCENT_GREEN))
                    } else if is_heading {
                        ("# ", Style::new().fg(Theme::ACCENT_BLUE).bold())
                    } else if is_list {
                        ("- ", Style::new().fg(Theme::ACCENT_CYAN))
                    } else if is_quote {
                        ("> ", Style::new().fg(Theme::TEXT_MUTED).italic())
                    } else {
                        ("- ", Style::new().fg(Theme::TEXT_SECONDARY))
                    };
                    rows.push((format!("{prefix}{compact}"), style));
                    if rows.len() >= max_lines {
                        return rows;
                    }
                    if is_fence {
                        in_fence = !in_fence;
                    }
                }
            }
            ContentBlock::Code { code, language, .. } => {
                let language = language
                    .as_deref()
                    .map(str::trim)
                    .filter(|value| !value.is_empty())
                    .unwrap_or("plain");
                let label = format!("[code:{language}]");
                if seen.insert(normalize_preview_line(&label)) {
                    rows.push((label, Style::new().fg(Theme::ACCENT_PURPLE).bold()));
                    if rows.len() >= max_lines {
                        return rows;
                    }
                }
                for line in code.lines() {
                    let trimmed = line.trim();
                    if trimmed.is_empty() {
                        continue;
                    }
                    if summary_hint
                        .is_some_and(|summary| detail_line_matches_summary(trimmed, summary))
                    {
                        continue;
                    }
                    let compact = compact_text_snippet(trimmed, DETAIL_PREVIEW_MAX_CHARS);
                    if compact.is_empty() {
                        continue;
                    }
                    if !seen.insert(normalize_preview_line(&compact)) {
                        continue;
                    }
                    rows.push((format!("| {compact}"), Style::new().fg(Theme::ACCENT_GREEN)));
                    if rows.len() >= max_lines {
                        return rows;
                    }
                }
            }
            ContentBlock::Json { data } => {
                if let Some(hint) = json_value_hint(data, 600) {
                    if !summary_hint
                        .is_some_and(|summary| detail_line_matches_summary(&hint, summary))
                    {
                        let compact = compact_text_snippet(&hint, DETAIL_PREVIEW_MAX_CHARS);
                        if compact.is_empty() {
                            continue;
                        }
                        if !seen.insert(normalize_preview_line(&compact)) {
                            continue;
                        }
                        rows.push((
                            format!("- {compact}"),
                            Style::new().fg(Theme::TEXT_SECONDARY),
                        ));
                        if rows.len() >= max_lines {
                            return rows;
                        }
                    }
                }
            }
            _ => {}
        }
    }
    rows
}

#[derive(Debug, Clone)]
struct FileReferenceLine {
    path: String,
    line_number: Option<usize>,
    message: String,
}

fn collect_grouped_file_reference_rows(
    text: &str,
    max_lines: usize,
) -> Option<Vec<(String, Style)>> {
    if max_lines == 0 {
        return None;
    }

    let mut groups: Vec<(String, Vec<String>)> = Vec::new();

    for line in text.lines() {
        let Some(entry) = parse_file_reference_line(line) else {
            continue;
        };

        let label = display_path_label(&entry.path);
        let detail = match entry.line_number {
            Some(line_number) => format!("L{line_number}: {}", entry.message),
            None => entry.message,
        };
        let detail_normalized = normalize_preview_line(&detail);
        if detail_normalized.is_empty() {
            continue;
        }

        if let Some((_, details)) = groups.iter_mut().find(|(path, _)| path == &label) {
            if details
                .iter()
                .all(|existing| normalize_preview_line(existing) != detail_normalized)
            {
                details.push(detail);
            }
        } else {
            groups.push((label, vec![detail]));
        }
    }

    let unique_details = groups
        .iter()
        .map(|(_, details)| details.len())
        .sum::<usize>();
    if unique_details < 2 {
        return None;
    }

    let mut rows = Vec::new();
    for (path, details) in groups {
        if rows.len() >= max_lines {
            break;
        }
        rows.push((path, Style::new().fg(Theme::ACCENT_BLUE).bold()));
        for detail in details {
            if rows.len() >= max_lines {
                break;
            }
            rows.push((
                format!("- {detail}"),
                Style::new().fg(Theme::TEXT_SECONDARY),
            ));
        }
    }

    if rows.is_empty() {
        None
    } else {
        Some(rows)
    }
}

fn parse_file_reference_line(line: &str) -> Option<FileReferenceLine> {
    let mut candidate = strip_detail_leading_marker(line.trim());
    candidate = trim_wrapping_quotes(candidate);
    if candidate.is_empty() {
        return None;
    }

    let split_at = candidate.find(':')?;
    let (path_raw, tail_raw) = candidate.split_at(split_at);
    let path = path_raw.trim();
    if !looks_like_file_path(path) {
        return None;
    }

    let mut tail = tail_raw.trim_start_matches(':').trim_start();
    let mut line_number = None;

    let digit_len = tail.chars().take_while(|ch| ch.is_ascii_digit()).count();
    if digit_len > 0 {
        let parsed = tail
            .get(..digit_len)
            .and_then(|digits| digits.parse::<usize>().ok());
        let rest = tail.get(digit_len..).unwrap_or("").trim_start();
        if rest.is_empty()
            || rest.starts_with(':')
            || rest.starts_with('-')
            || rest.starts_with('"')
            || rest.starts_with('\'')
        {
            line_number = parsed;
            tail = rest
                .trim_start_matches(':')
                .trim_start()
                .trim_start_matches('-')
                .trim_start();
        }
    }

    tail = strip_detail_leading_marker(tail);
    tail = trim_wrapping_quotes(tail);
    let message = compact_text_snippet(tail, 100);
    if message.is_empty() || is_low_signal_text_line(&message) {
        return None;
    }

    Some(FileReferenceLine {
        path: path.to_string(),
        line_number,
        message,
    })
}

fn strip_detail_leading_marker(line: &str) -> &str {
    let mut current = line.trim_start();
    loop {
        let next = if let Some(rest) = current.strip_prefix("└") {
            Some(rest)
        } else if let Some(rest) = current.strip_prefix("├") {
            Some(rest)
        } else if let Some(rest) = current.strip_prefix("│") {
            Some(rest)
        } else if let Some(rest) = current.strip_prefix("·") {
            Some(rest)
        } else if let Some(rest) = current.strip_prefix("•") {
            Some(rest)
        } else if let Some(rest) = current.strip_prefix("- ") {
            Some(rest)
        } else if let Some(rest) = current.strip_prefix("* ") {
            Some(rest)
        } else {
            current.strip_prefix(". ")
        };

        if let Some(rest) = next {
            current = rest.trim_start();
            continue;
        }
        break;
    }
    current
}

fn trim_wrapping_quotes(text: &str) -> &str {
    let trimmed = text.trim();
    if trimmed.len() >= 2 {
        let quoted = (trimmed.starts_with('"') && trimmed.ends_with('"'))
            || (trimmed.starts_with('\'') && trimmed.ends_with('\''));
        if quoted {
            return trimmed
                .get(1..trimmed.len().saturating_sub(1))
                .map(str::trim)
                .unwrap_or(trimmed);
        }
    }
    trimmed
}

fn looks_like_file_path(path: &str) -> bool {
    let trimmed = path.trim();
    if trimmed.is_empty() {
        return false;
    }
    let lower = trimmed.to_ascii_lowercase();
    if lower.starts_with("http://") || lower.starts_with("https://") {
        return false;
    }

    let normalized = trimmed.replace('\\', "/");
    if !normalized.contains('/') {
        return false;
    }
    let last = normalized.rsplit('/').next().unwrap_or("");
    !last.is_empty() && (last.contains('.') || normalized.contains('[') || normalized.contains(']'))
}

fn looks_like_markdown_list_item(line: &str) -> bool {
    let trimmed = line.trim_start();
    if trimmed.starts_with("- ") || trimmed.starts_with("* ") || trimmed.starts_with("+ ") {
        return true;
    }
    let mut seen_digit = false;
    for ch in trimmed.chars() {
        if ch.is_ascii_digit() {
            seen_digit = true;
            continue;
        }
        if seen_digit && matches!(ch, '.' | ')') {
            return true;
        }
        break;
    }
    false
}

fn strip_markdown_heading_marker(line: &str) -> &str {
    let stripped = line.trim_start().trim_start_matches('#').trim_start();
    if stripped.is_empty() {
        line.trim()
    } else {
        stripped
    }
}

fn strip_markdown_quote_marker(line: &str) -> &str {
    let stripped = line.trim_start().trim_start_matches('>').trim_start();
    if stripped.is_empty() {
        line.trim()
    } else {
        stripped
    }
}

fn strip_markdown_fence_marker(line: &str) -> &str {
    let stripped = line
        .trim_start()
        .trim_start_matches('`')
        .trim_start_matches('~')
        .trim_start();
    if stripped.is_empty() {
        line.trim()
    } else {
        stripped
    }
}

fn strip_markdown_list_marker(line: &str) -> &str {
    let trimmed = line.trim_start();
    if let Some(rest) = trimmed
        .strip_prefix("- ")
        .or_else(|| trimmed.strip_prefix("* "))
        .or_else(|| trimmed.strip_prefix("+ "))
    {
        return rest.trim_start();
    }

    let mut index = 0usize;
    let chars: Vec<char> = trimmed.chars().collect();
    while index < chars.len() && chars[index].is_ascii_digit() {
        index += 1;
    }
    if index > 0 && index < chars.len() && matches!(chars[index], '.' | ')') {
        let mut byte_index = index + 1;
        let bytes = trimmed.as_bytes();
        while byte_index < bytes.len() && bytes[byte_index].is_ascii_whitespace() {
            byte_index += 1;
        }
        return trimmed
            .get(byte_index..)
            .map(str::trim_start)
            .filter(|value| !value.is_empty())
            .unwrap_or(trimmed);
    }

    trimmed
}

fn normalize_preview_line(text: &str) -> String {
    let inline_cleaned = strip_inline_markdown_markers(text);
    inline_cleaned
        .replace("```", " ")
        .replace('…', " ")
        .replace("...", " ")
        .replace(['·', '|', '#', '>', '[', ']'], " ")
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
        .trim()
        .to_ascii_lowercase()
}

fn detail_line_matches_summary(line: &str, summary: &str) -> bool {
    let line_variants = [line.trim(), strip_summary_event_prefix(line)];
    let summary_variants = [summary.trim(), strip_summary_event_prefix(summary)];

    for line_variant in line_variants {
        let normalized_line = normalize_preview_line(line_variant);
        if normalized_line.is_empty() {
            continue;
        }
        for summary_variant in summary_variants {
            let normalized_summary = normalize_preview_line(summary_variant);
            if normalized_summary.is_empty() {
                continue;
            }
            if normalized_line_pair_matches(&normalized_line, &normalized_summary) {
                return true;
            }
        }
    }

    false
}

fn normalized_line_pair_matches(line: &str, summary: &str) -> bool {
    line == summary
        || line.contains(summary)
        || summary.contains(line)
        || line.starts_with(summary)
        || summary.starts_with(line)
}

fn strip_summary_event_prefix(text: &str) -> &str {
    let trimmed = text.trim_start();
    for prefix in ["start ", "end ", "status ", "result "] {
        if let Some(rest) = trimmed.strip_prefix(prefix) {
            return rest.trim_start();
        }
    }
    if let Some(rest) = trimmed.strip_prefix("error:") {
        return rest.trim_start();
    }
    trimmed
}

