        app.view = View::SessionList;
        terminal
            .draw(|frame| {
                let area = frame.area();
                render(frame, area, &app);
            })
            .expect("draw");

        let text = buffer_to_string(terminal.backend().buffer());
        assert!(text.contains("Keyboard Shortcuts"));
        assert!(text.contains("Current Context: Session List"));
